#!/usr/bin/env bash
# Generated by build_cd38_external_tool_runbook.py
# Run only the CD38 external-tool actions that are still missing from the action plan.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"

require_command() {
  if ! command -v "$1" >/dev/null 2>&1; then
    echo "Required command not found in PATH: $1" >&2
    exit 2
  fi
}

require_file() {
  if [[ ! -f "$1" ]]; then
    echo "Required input file not found: $1" >&2
    exit 3
  fi
}

require_command "prank"
require_command "fpocket"

echo "Running 4 CD38 external-tool action(s)."

echo "[1/4] 3ROP fpocket"
RUN_DIR="$SCRIPT_DIR/fpocket_runs/3ROP"
RUN_PDB="$RUN_DIR/3ROP.pdb"
require_file "$RUN_PDB"
(cd "$RUN_DIR" && fpocket -f "3ROP.pdb")

echo "[2/4] 4OGW fpocket"
RUN_DIR="$SCRIPT_DIR/fpocket_runs/4OGW"
RUN_PDB="$RUN_DIR/4OGW.pdb"
require_file "$RUN_PDB"
(cd "$RUN_DIR" && fpocket -f "4OGW.pdb")

echo "[3/4] 3F6Y fpocket"
RUN_DIR="$SCRIPT_DIR/fpocket_runs/3F6Y"
RUN_PDB="$RUN_DIR/3F6Y.pdb"
require_file "$RUN_PDB"
(cd "$RUN_DIR" && fpocket -f "3F6Y.pdb")

echo "[4/4] 3F6Y p2rank"
PDB_PATH="$SCRIPT_DIR/pdbs/3F6Y.pdb"
OUT_DIR="$SCRIPT_DIR/p2rank_outputs/3F6Y"
mkdir -p "$OUT_DIR"
require_file "$PDB_PATH"
prank predict -f "$PDB_PATH" -o "$OUT_DIR"

echo "External-tool actions finished."
echo "Return the whole package folder or zip it, then import/finalize in the original ML project."
